            margin-bottom: 8px;
            font-weight: 500;
            color: var(--text-secondary);
            font-size: 13px;
        }

        .form-control {
            width: 100%;
            padding: 14px 16px;
            background: #1a1a2e !important;
            border: 1px solid #3f3f46 !important;
            border-radius: 12px;
            font-size: 14px;
            color: #ffffff !important;
